SIGIL              = "!"
UNSOLICITED_WINDOW = 600
SALIENCE_THRESHOLD = 0.65

state = { "memory": load_memory(), "last_push_ts": 0 }

function audit(kind, payload):
    append_audit_log({
        "ts":   now_iso(),
        "kind": kind,                # "sigil" | "push" | "rejected"
        "payload": payload,
    })

function on_user_message(text):
    if text.startswith(SIGIL):
        verb, args = parse_sigil(text[1:])
        apply_to_memory(state.memory, verb, args)
        audit("sigil", {"verb": verb, "args": args})
        return ack(verb)
    return agent.reply(text, state)

function on_agent_tick():
    candidate = agent.scan_for_signal(state)
    if candidate is none: return
    score = salience_score(candidate, state)      # salience-triggered-output
    if score < SALIENCE_THRESHOLD:
        audit("rejected", {"reason": "sub-threshold", "score": score})
        return
    if now() - state.last_push_ts < UNSOLICITED_WINDOW:
        audit("rejected", {"reason": "rate-limit"})
        return
    for chunk in stream_push(candidate.message):  # one channel, streamed
        emit(chunk)
    state.last_push_ts = now()
    audit("push", {"score": score, "summary": candidate.summary})
# Why this works: salience gates the push, the channel still carries both
# sides on one surface, and the audit log gives ops a single record of
# every sigil and every push without a second sidecar.
# Related: see `salience-triggered-output`, `decision-log`, `streaming-typed-events`.

CITATION_RE = /\[\[cite:([a-z0-9_-]+)\]\]/

function stream_with_citations(question, sources):
    prompt = build_prompt(question, sources, marker="[[cite:<id>]]")
    citations_seen = {}

    for chunk in llm.stream(prompt):
        text = chunk.delta
        cursor = 0
        for match in CITATION_RE.find_all(text):
            if match.start > cursor:
                yield {"type": "text_delta", "text": text[cursor:match.start]}
            cid = match.group(1)
            src = sources.get(cid)
            if src and cid not in citations_seen:
                citations_seen[cid] = src
            yield {"type": "citation", "id": cid, "source": src}
            cursor = match.end
        if cursor < len(text):
            yield {"type": "text_delta", "text": text[cursor:]}

    yield {"type": "done", "citations": citations_seen}

