DELAY_STEPS      = 16          # latency budget, in shared-axis steps
MAX_BUFFER       = 64          # backpressure ceiling on the source
FINALISE_AFTER   = 4           # steps a token must persist to be "final"

state = {
    "buffer":   [],            # incoming source tokens
    "emitted":  [],            # (step, token, marker) tuples
    "cancel":   new_cancel_token(),
}

function decode_stream(stream_source):
    for src_tok in stream_source:
        if state.cancel.fired():
            emit_marker("cancelled"); return
        if len(state.buffer) >= MAX_BUFFER:
            yield_to_source()                       # backpressure
            continue
        state.buffer.append(src_tok)
        out = model.step(src_tok)                   # offset-aligned next pair
        if len(state.buffer) <= DELAY_STEPS:
            continue                                # still inside the offset
        tentative = out.target_token
        emit(tentative, marker="tentative")         # partial-result render
        state.emitted.append((len(state.buffer), tentative, "tentative"))
        finalise_old_emissions()

function finalise_old_emissions():
    cutoff = len(state.buffer) - FINALISE_AFTER
    for i, (step, tok, marker) in enumerate(state.emitted):
        if marker == "tentative" and step <= cutoff:
            emit_marker("final", index=i, token=tok)
            state.emitted[i] = (step, tok, "final")

function on_barge_in():
    state.cancel.fire()                             # interrupt mid-stream
# Why this works: the offset itself remains the read/write policy, but
# the wrapping loop adds the three production concerns DSM alone ignores
# - backpressure on the source, a cancel token for barge-in, and
# consistency markers so the UI can replace tentative tokens cleanly.
# Related: see `streaming-typed-events`, `stop-cancel`.

