function stream_reply(user_text):
    shape  = derive_shape(state.proxy)
    prompt = assemble(user_text, shape)
    state.cancel = new_cancel_token()
    stream = model.generate_stream(prompt, cancel=state.cancel)
    emitted = []
    for chunk in stream:
        if state.cancel.fired():
            for i in 0..len(emitted)-1:
                emit_marker("tentative", index=i)
            emit_marker("reshape", reason="proxy changed")
            return restart_with(state.proxy, user_text)
        emit(chunk, marker="tentative")
        emitted.append(chunk)
    emit_marker("final")

