# Why this works: the proxy is hot-reloaded under a file watcher so an
# in-flight reply can be cancelled the moment the human's state changes,
# and consistency markers let the UI redraw the partial answer in the
# new shape instead of stranding tokens written for the old one.
# Related: see `liminal-state-detection`, `now-anchoring`.

PROXY_PATH = "~/.agent/proxy.json"

interrupts = new_queue()
state      = { "proxy": read_or_default(PROXY_PATH) }

watch_file(PROXY_PATH, on_change=function(new_proxy):
    interrupts.push({"kind": "proxy_changed", "proxy": new_proxy})
)

function agent_loop(user_text):
    plan = planner.make(user_text, proxy=state.proxy)
    for step in plan:
        # Drain interrupts BEFORE each step — interruptible-agent-execution
        while not interrupts.empty():
            ev = interrupts.pop()
            if ev.kind == "proxy_changed":
                state.proxy = ev.proxy
                plan = planner.replan(remaining=plan.from(step),
                                      proxy=state.proxy)
                emit_marker("replanned", reason="proxy")
                break
        for chunk in step.run_stream(proxy=state.proxy):
            emit(chunk)

function prompt_shape(proxy):
    if proxy.energy <= 3 or proxy.fatigue >= 7:
        return "short; one anchor; do not open new threads"
    if proxy.environment == "winding-down":
        return "stay present; no homework"
    return "normal"
# Why this works: the proxy file becomes the source of interrupts, the
# interruptible loop drains them between steps, and the planner gets
# the new shape before producing more tokens — so a tired user does
# not finish a long-form answer they did not want.
# Related: see `interruptible-agent-execution`, `liminal-state-detection`.

function run_agent(task, cancel_token):
    messages = [system_prompt, user(task)]
    partial  = ""

    for step in 1..MAX_STEPS:
        if cancel_token.is_set():
            return halt("cancelled", partial=partial, step=step)

        stream = llm.stream(messages=messages, tools=TOOLS,
                            cancel_token=cancel_token)
        for chunk in stream:
            if cancel_token.is_set():
                stream.close()                       # tear down provider stream
                return halt("cancelled", partial=partial, step=step)
            partial += chunk.text
            ui.emit("text_delta", chunk.text)

        reply = finalise(stream)
        messages.append(reply)
        if not reply.tool_calls:
            return ok(reply.content, step=step)

        for call in reply.tool_calls:
            result = dispatch(call, cancel_token=cancel_token)  # tools honour the token
            if cancel_token.is_set():
                return halt("cancelled", partial=partial, step=step)
            messages.append(tool_result(call.id, result))

    return halt("budget_exhausted", partial=partial, step=MAX_STEPS)

