interface Voice:
    capabilities: set      # subset of {"tts", "stt", "sts"}
    voices:       list

    function speak(text)        -> AudioStream
    function listen(audio)      -> TranscriptStream
    function converse(audio)    -> AudioStream     # realtime speech-to-speech

# Shared event vocabulary every implementation emits:
#   turn_start | partial_transcript | final_transcript
#   voice_activity_start | voice_activity_stop
#   barge_in   | audio_chunk | turn_end

function run_voice_agent(voice: Voice, mic, speaker):
    if "sts" in voice.capabilities:
        out = voice.converse(mic.stream())
        for ev in out:
            route(ev, speaker)                    # one path, realtime
        return

    require({"tts", "stt"}.issubset(voice.capabilities), "need tts+stt")
    for ev in voice.listen(mic.stream()):
        if ev.type == "final_transcript":
            reply = agent.reply(ev.text)
            for chunk in voice.speak(reply):
                speaker.play(chunk)
        elif ev.type == "barge_in":
            speaker.cancel()                      # stop_cancel hook
# The loop branches on capability, never on provider name.

MAX_AUDIO_BUFFER = 250    # ms of audio queued before mic backpressures

state = {
    "turn_id":  new_turn_id(),
    "cancel":   new_cancel_token(),
    "resume":   load_persisted("resume_cursor", default=none),
}

function run_voice_agent(voice: Voice, mic, speaker):
    if "sts" in voice.capabilities:
        run_sts(voice, mic, speaker); return
    require({"tts", "stt"}.issubset(voice.capabilities))
    run_cascade(voice, mic, speaker)

function run_sts(voice, mic, speaker):
    src = mic.stream(max_buffer_ms=MAX_AUDIO_BUFFER)   # backpressure
    for ev in voice.converse(src, resume=state.resume, cancel=state.cancel):
        if ev.type == "barge_in":
            speaker.cancel()
            state.cancel.fire()
        elif ev.type == "partial_transcript":
            emit(ev, marker="tentative")
        elif ev.type == "final_transcript":
            emit(ev, marker="final")
        elif ev.type == "audio_chunk":
            speaker.play(ev.audio)
        elif ev.type == "turn_end":
            state.resume = ev.cursor
            persist("resume_cursor", state.resume)     # reconnect survives
            state.turn_id = new_turn_id()
            state.cancel  = new_cancel_token()

function run_cascade(voice, mic, speaker):
    src = mic.stream(max_buffer_ms=MAX_AUDIO_BUFFER)
    for ev in voice.listen(src, resume=state.resume):
        if ev.type == "partial_transcript":
            emit(ev, marker="tentative")
        elif ev.type == "final_transcript":
            emit(ev, marker="final")
            reply  = agent.reply(ev.text)
            state.cancel = new_cancel_token()
            for chunk in voice.speak(reply, cancel=state.cancel):
                speaker.play(chunk)
# Why this works: the capability branch stays at the top, but every
# branch carries the same production wiring - mic backpressure caps
# buffering, a cancel token handles barge-in, partial/final markers
# drive the visible transcript, and persisted resume cursors let a
# dropped connection pick up at the right turn.
# Related: see `stop-cancel`, `streaming-typed-events`.

