SHORT_PAUSE = 0.2   # commit fast once the thought looks complete
LONG_PAUSE  = 0.8   # acoustic floor: commit eventually even if unsure

def listen_for_turn():
    transcript = ""
    silence = 0.0
    while True:
        frame = mic.next_frame()
        if vad.is_speech(frame):
            silence = 0.0
            transcript = stt.update(frame)          # streaming partial
        else:
            silence += frame.duration
        complete = turn_model.is_complete(transcript)  # semantic score
        if complete and silence >= SHORT_PAUSE:
            return transcript                        # fast commit
        if silence >= LONG_PAUSE:
            return transcript                        # timeout floor

def speak(reply):
    tts.start(reply)
    while tts.playing():
        frame = mic.next_frame()
        if not vad.is_speech(frame):
            continue
        kind = barge_classifier.label(stt.update(frame))
        if kind == "backchannel":
            continue                                 # 'uh-huh' -> keep talking
        if kind == "barge_in":
            tts.duck()                               # yield the floor
            return INTERRUPTED
    return DONE

while call.active():
    user = listen_for_turn()
    speak(agent.respond(user))
